#include <stdio.h>
#include <string.h>
int main() {
    int n, m;
    scanf("%d", &n);
    char city[n][5];
    for (int i = 0; i < n; i++) {
        scanf("%s", city[i]);
    }
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        char city1[5], city2[5];
        scanf("%s %s", city1, city2);
        int count = 0;
        for (int j = 0; j < 4; j++) {
            for (int k = 0; k < 4; k++) {
                if (city1[j] == city2[k]) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

