const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let n = parseInt(lines[0]);
    let city = lines.slice(1, n + 1);
    let m = parseInt(lines[n + 1]);
    for (let i = 0; i < m; i++) {
        let [city1, city2] = lines[n + 2 + i].split(' ');
        let count = 0;
        for (let j = 0; j < 4; j++) {
            for (let k = 0; k < 4; k++) {
                if (city1[j] == city2[k]) {
                    count++;
                }
            }
        }
        console.log(count);
    }
});
